const crypto = require('crypto');

function hashPassword(password) {
  return new Promise((resolve, reject) => {
    crypto.hash(password, 'sha256', (err, hash) => {
      if (err) return reject(err);
      resolve(hash.toString('base64'));
    });
  });
}